#!/usr/bin/env python3
"""
Dimensional Memory Constant (Standalone Evolving System)
=========================================================

This single file contains the complete, standalone Dimensional Processing
System. It is a "living" system that can learn and evolve.

This is the "PERFECTED" module, implementing:
1.  **Inherited Governance ("Mutation"):** Parent Laws (like JSON) can
    "mutate" the logic of Child Laws (like Security).
2.  **Generational Linking ("Cross-Law"):** The system uses recursion
    to process nested data, creating two-way parent-child links
    between DataNodes.
"""

import threading
import queue
import json
import time
import os
import uuid
import logging
import random
import hashlib
import math
from dataclasses import dataclass, field
from typing import Any, Dict, List, Optional, Tuple, Callable

# --- Configuration Constants ---
BASE_SAVE_FILE = "system_base_state.json"
DELTA_LOG_FILE = "system_live.deltalog"
TEMP_SAVE_FILE = "system_base_state.tmp"
MERGE_INTERVAL_SECONDS = 30  # Run merge every 30 seconds for testing
LOG_FORMAT = '%(asctime)s - %(threadName)s - %(levelname)s - %(message)s'
logging.basicConfig(level=logging.INFO, format=LOG_FORMAT)

# --- Pattern Memory Constants ---
RELIABILITY_SATURATION = 10.0
VITALITY_THRESHOLD = 0.2
MIN_AGE_BEFORE_PRUNE = 5.0  # Seconds, for demo speed (usually days)
MAX_PATTERN_DIMS = 10

# --- Global "Live Save" Components ---
SAVE_QUEUE = queue.Queue()
_save_thread_active = threading.Event()
_merge_thread_active = threading.Event()


# ============================================================================
# 1. CORE DATA STRUCTURES (The "Autonomic" System)
# ============================================================================

@dataclass
class DataNode:
    """
    The smallest unit of data. It includes the "live save" trigger.
    (No changes were needed for perfection)
    """
    id: str = field(default_factory=lambda: str(uuid.uuid4()))
    dimension_links: List[str] = field(default_factory=list)
    payload: Dict[str, Any] = field(default_factory=dict)
    last_modified_timestamp: float = field(default_factory=time.time)

    def modify(self, payload_update: Dict[str, Any] = None, link_update: List[str] = None):
        """
        The "Setter" function. This is the "live" part of the "live save."
        It updates the node and pushes it to the save queue.
        """
        modified = False

        if payload_update:
            for key, value in payload_update.items():
                if self.payload.get(key) != value:
                    self.payload[key] = value
                    modified = True

        if link_update:
            for link in link_update:
                if link not in self.dimension_links:
                    self.dimension_links.append(link)
                    modified = True

        if modified:
            logging.info(f"Modifying Node {self.id}...")
            self.last_modified_timestamp = time.time()
            SAVE_QUEUE.put(self)
            logging.info(f"Node {self.id} queued for live save.")

    def to_dict(self):
        return {
            "id": self.id, "dimension_links": self.dimension_links,
            "payload": self.payload, "last_modified_timestamp": self.last_modified_timestamp
        }

    @staticmethod
    def from_dict(data: Dict):
        return DataNode(
            id=data.get('id', str(uuid.uuid4())),
            dimension_links=data.get('dimension_links', []),
            payload=data.get('payload', {}),
            last_modified_timestamp=data.get('last_modified_timestamp', time.time())
        )


# ============================================================================
# 2. PATTERN DISTILLATION & MEMORY (New Internal Layer)
# ============================================================================

@dataclass
class PatternSignal:
    """Anonymous, distilled signal ready for pattern memory."""
    concept_base: str
    dimensions: List[str]
    abstract_payload: Dict[str, Any]

class PatternDistiller:
    """
    Gatekeeper: Converts raw data to Pattern Signals.
    Strips PII, generalizes values, and ensures anonymity.
    """
    @staticmethod
    def distill(domain: str, raw_data: Dict[str, Any]) -> Optional[PatternSignal]:
        if domain == "SECURITY":
            return PatternDistiller._distill_security(raw_data)
        elif domain == "TEXT":
            return PatternDistiller._distill_text(raw_data)
        elif domain == "CLIMATE":
            return PatternDistiller._distill_climate(raw_data)
        return None

    @staticmethod
    def pattern_key(signal: PatternSignal) -> str:
        """Deterministic hash of the pattern structure."""
        # Sort dimensions to ensure order independence
        dims_str = ",".join(sorted(signal.dimensions))
        # Version 1 schema key
        key_content = f"v1|{signal.concept_base}|{dims_str}"
        return hashlib.sha256(key_content.encode('utf-8')).hexdigest()[:16]

    @staticmethod
    def _distill_security(data: Dict[str, Any]) -> PatternSignal:
        # Anonymize IP: Internal/External/Subnet
        ip = data.get("ip", "")
        context = "internal" if ip.startswith("192.168") or ip.startswith("10.") else "external"

        # Generalize Action
        action = data.get("action", "unknown")

        # Bucket Threat
        threat = data.get("threat_level", 0.0)
        threat_bucket = "high" if threat > 0.7 else "medium" if threat > 0.3 else "low"

        return PatternSignal(
            concept_base="SEC_Event",
            dimensions=[f"dim_context:{context}", f"dim_action:{action}", f"dim_threat:{threat_bucket}"],
            abstract_payload={"roles": ["security", "threat_indicator"]}
        )

    @staticmethod
    def _distill_text(data: Dict[str, Any]) -> Optional[PatternSignal]:
        # NEVER store raw text.
        text = data.get("text", "")
        if not text: return None

        length_bucket = "long" if len(text) > 100 else "short"
        # Simple keyword sentiment for demo
        sentiment = "positive" if "good" in text or "track" in text else "negative" if "fail" in text else "neutral"

        return PatternSignal(
            concept_base="TXT_Sentiment",
            dimensions=[f"dim_len:{length_bucket}", f"dim_sentiment:{sentiment}"],
            abstract_payload={"roles": ["communication"]}
        )

    @staticmethod
    def _distill_climate(data: Dict[str, Any]) -> PatternSignal:
        anomaly = data.get("anomaly", "none")
        return PatternSignal(
            concept_base="ENV_Sensor",
            dimensions=[f"dim_anomaly:{anomaly}"],
            abstract_payload={"roles": ["environment"]}
        )

class PatternMemoryEngine:
    """
    Manages the lifecycle of Pattern Nodes within the Dimensional Memory.
    Handles promotion, deduplication, and reinforcement (Beta-Bernoulli).
    """
    def __init__(self, memory_system):
        self.memory = memory_system

    def promote(self, domain: str, raw_data: Dict[str, Any]):
        """
        Public API: Distill and Reinforce.
        """
        signal = PatternDistiller.distill(domain, raw_data)
        if not signal:
            return # Ignore noise/unknown domains

        p_key = PatternDistiller.pattern_key(signal)
        concept_name = f"PATTERN::{domain}::{p_key}"

        # Check if exists
        node_id = self.memory.find_node_id_by_concept(concept_name)

        if node_id:
            # REINFORCE existing
            node = self.memory.get_node(node_id)
            self._reinforce_node(node)
        else:
            # CREATE new
            self._create_pattern_node(concept_name, signal, domain)

    def _create_pattern_node(self, concept_name: str, signal: PatternSignal, domain: str):
        # Initialize Beta-Bernoulli stats
        # alpha=1, beta=1 is the uninformative prior (Laplace smoothing)
        stats = {
            "evidence_count": 1,
            "first_seen": time.time(),
            "last_seen": time.time(),
            "alpha": 1.0,
            "beta": 1.0,
            "strength": 0.5, # 1/(1+1)
            "reliability": 0.0,
            "half_life_s": 10.0 # Fast decay for demo
        }

        payload = {
            "concept": concept_name,
            "is_pattern": True,
            "roles": signal.abstract_payload.get("roles", []),
            "stats": stats
        }

        dims = [
            "dim_theme:pattern",
            f"dim_domain:{domain}",
            "dim_pattern_schema:v1"
        ] + signal.dimensions

        new_node = DataNode(
            payload=payload,
            dimension_links=dims
        )
        self.memory.add_node(new_node)
        logging.info(f"PATTERN ENGINE: Created new pattern {concept_name}")

    def _reinforce_node(self, node: DataNode):
        stats = node.payload.get("stats", {})

        # Update Stats
        stats["evidence_count"] = stats.get("evidence_count", 0) + 1
        stats["last_seen"] = time.time()
        stats["alpha"] = stats.get("alpha", 1.0) + 1.0 # Positive evidence

        # Recompute derived metrics
        alpha = stats["alpha"]
        beta = stats.get("beta", 1.0)
        stats["strength"] = alpha / (alpha + beta)

        # Reliability saturates logarithmically with evidence
        # reliability = log(1 + count) / log(1 + SATURATION)
        # Capped at 1.0
        stats["reliability"] = min(1.0, math.log(1 + stats["evidence_count"]) / math.log(1 + RELIABILITY_SATURATION))

        node.payload["stats"] = stats
        node.modify(payload_update={"stats": stats})
        logging.info(f"PATTERN ENGINE: Reinforced {node.payload['concept']} (Count: {stats['evidence_count']})")


class DimensionalMemory:
    """
    The "Universe" object. Holds all DataNodes and provides
    fast, indexed access. This is the "unconscious" part of the brain.
    """
    def __init__(self):
        self.nodes: Dict[str, DataNode] = {}
        self.dimension_index: Dict[str, List[str]] = {}
        self.concept_index: Dict[str, str] = {}
        self.last_global_save_timestamp: float = 0.0
        self._load_from_base_file()

    def _load_from_base_file(self):
        logging.info(f"Loading from {BASE_SAVE_FILE}...")
        if not os.path.exists(BASE_SAVE_FILE):
            logging.warning(f"{BASE_SAVE_FILE} not found. Starting fresh.")
            return
        try:
            with open(BASE_SAVE_FILE, 'r') as f:
                data = json.load(f)
            self.last_global_save_timestamp = data.get('last_global_save_timestamp', 0.0)
            loaded_nodes = data.get('nodes', {})
            for node_id, node_data in loaded_nodes.items():
                node = DataNode.from_dict(node_data)
                self.nodes[node_id] = node
                self._update_indices(node)
            logging.info(f"Load complete. {len(self.nodes)} nodes loaded.")
        except Exception as e:
            logging.error(f"CRITICAL: Failed to load {BASE_SAVE_FILE}. Error: {e}")

    def _update_indices(self, node: DataNode):
        for link in node.dimension_links:
            if link not in self.dimension_index:
                self.dimension_index[link] = []
            if node.id not in self.dimension_index[link]:
                self.dimension_index[link].append(node.id)
        concept = node.payload.get("concept")
        if concept:
            self.concept_index[concept] = node.id

    def add_node(self, node: DataNode):
        if node.id in self.nodes:
            logging.warning(f"Node {node.id} already exists. Overwriting.")
        self.nodes[node.id] = node
        self._update_indices(node)
        node.modify() # Trigger the save queue

    def modify_node(self, node_id: str, payload_update: Dict[str, Any] = None, link_update: List[str] = None):
        if node_id not in self.nodes:
            logging.error(f"Modify failed: Node {node_id} not found.")
            return
        node = self.nodes[node_id]
        node.modify(payload_update, link_update)
        if link_update or (payload_update and "concept" in payload_update):
            self._update_indices(node)

    def get_node(self, node_id: str) -> Optional[DataNode]:
        return self.nodes.get(node_id)

    def find_node_id_by_concept(self, concept_name: str) -> Optional[str]:
        return self.concept_index.get(concept_name)


