from __future__ import annotations

import os
import time
import hashlib
from dataclasses import asdict
from typing import Any, Dict, Optional, Tuple

from flask import Flask, jsonify, request

# Core engine surface (keep imports local to avoid circularity in your tree)
try:
    from vector.predict import PredictionService  # type: ignore
except Exception:
    PredictionService = None  # Allows this file to exist even if engine files are mid-refactor.

app = Flask(__name__)

# ---------------------------
# Auth: API Keys
# ---------------------------

def _load_api_keys() -> set[str]:
    keys: set[str] = set()
    env_keys = os.environ.get("VECTOR_API_KEYS", "").strip()
    if env_keys:
        keys |= {k.strip() for k in env_keys.split(",") if k.strip()}

    key_file = os.environ.get("VECTOR_API_KEYS_FILE", "").strip()
    if key_file and os.path.exists(key_file):
        with open(key_file, "r", encoding="utf-8") as f:
            for line in f:
                k = line.strip()
                if k and not k.startswith("#"):
                    keys.add(k)
    return keys

_ALLOWED_KEYS = _load_api_keys()

def _get_api_key() -> Optional[str]:
    auth = request.headers.get("Authorization", "")
    if auth.lower().startswith("bearer "):
        return auth.split(None, 1)[1].strip() or None
    # fallback header for simple clients
    alt = request.headers.get("X-API-Key", "").strip()
    return alt or None

def _require_api_key() -> str:
    key = _get_api_key()
    if not key or (_ALLOWED_KEYS and key not in _ALLOWED_KEYS):
        # If _ALLOWED_KEYS is empty, allow all keys (dev mode).
        # For production, always set VECTOR_API_KEYS / VECTOR_API_KEYS_FILE.
        raise PermissionError("Unauthorized: missing/invalid API key")
    return key

def _key_fingerprint(key: str) -> str:
    # Do not log raw keys. Fingerprint is safe for logs/metrics.
    return hashlib.sha256(key.encode("utf-8")).hexdigest()[:12]


# ---------------------------
# Rate limiting + metering
# ---------------------------

_RPM = int(os.environ.get("VECTOR_RATE_LIMIT_RPM", "60"))
_WINDOW_SECONDS = 60

# in-memory window: { (key_fp): (window_start_ts, count) }
_RATE: dict[str, Tuple[float, int]] = {}

# simple usage counters: { key_fp: {"ingest": n, "evaluate": n, "scenario": n, "state": n} }
_USAGE: dict[str, Dict[str, int]] = {}

def _rate_check(key_fp: str) -> None:
    now = time.time()
    start, count = _RATE.get(key_fp, (now, 0))
    if now - start >= _WINDOW_SECONDS:
        start, count = now, 0
    count += 1
    _RATE[key_fp] = (start, count)
    if _RPM > 0 and count > _RPM:
        raise RuntimeError(f"Rate limit exceeded: {_RPM} requests/min")

def _bump_usage(key_fp: str, endpoint: str) -> None:
    if key_fp not in _USAGE:
        _USAGE[key_fp] = {"ingest": 0, "evaluate": 0, "scenario": 0, "state": 0}
    if endpoint in _USAGE[key_fp]:
        _USAGE[key_fp][endpoint] += 1


