#!/usr/bin/env python3
\"\"\"Vector Vault

Lightweight persistence for:
- normalized variables (as StoredVar)
- metadata
- simple snapshot/restore semantics (for scenario evaluation)

Design goals:
- No numpy
- Pure Python, JSON persistence
- Deterministic structure
\"\"\"

from __future__ import annotations

import json
import os
import time
from dataclasses import dataclass, asdict
from typing import Any, Dict, Optional

from vector.laws import Law

@dataclass
class StoredVar:
    name: str
    value: float
    law: Law
    confidence: float = 1.0
    provenance: str = "observed"
    ts: float = 0.0
    meta: Dict[str, Any] | None = None

    def to_json(self) -> Dict[str, Any]:
        d = asdict(self)
        d["law"] = self.law.value if hasattr(self.law, "value") else str(self.law)
        return d

    @staticmethod
    def from_json(d: Dict[str, Any]) -> "StoredVar":
        law_raw = d.get("law", "ENERGY")
        try:
            law = Law(law_raw)
        except Exception:
            law = Law.ENERGY
        return StoredVar(
            name=str(d.get("name", "")),
            value=float(d.get("value", 0.0)),
            law=law,
            confidence=float(d.get("confidence", 1.0)),
            provenance=str(d.get("provenance", "observed")),
            ts=float(d.get("ts", 0.0)),
            meta=d.get("meta") or {},
        )

class VectorVault:
    def __init__(self, storage_path: str = "/tmp/vector_vault.json"):
        self.storage_path = storage_path
        self.variables: Dict[str, StoredVar] = {}
        self.metadata: Dict[str, Any] = {}
        self._load()

    # -----------------------
    # Persistence
    # -----------------------
    def _load(self) -> None:
        if not self.storage_path:
            return
        if not os.path.exists(self.storage_path):
            return
        try:
            with open(self.storage_path, "r", encoding="utf-8") as f:
                raw = json.load(f)
            self.metadata = raw.get("metadata") or {}
            vars_raw = raw.get("variables") or {}
            self.variables = {k: StoredVar.from_json(v) for k, v in vars_raw.items()}
        except Exception:
            # corrupt vault -> start fresh (caller can manage backups)
            self.variables = {}
            self.metadata = {}

    def _save(self) -> None:
        if not self.storage_path:
            return
        os.makedirs(os.path.dirname(self.storage_path), exist_ok=True)
        payload = {
            "metadata": self.metadata,
            "variables": {k: v.to_json() for k, v in self.variables.items()},
        }
        tmp = self.storage_path + ".tmp"
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(payload, f, indent=2, sort_keys=True)
        os.replace(tmp, self.storage_path)

    # -----------------------
    # Public API
    # -----------------------
    def set_metadata(self, meta: Dict[str, Any]) -> None:
        self.metadata.update(meta or {})
        self._save()

    def upsert_shards(self, shards: Dict[str, Any]) -> None:
        \"\"\"Accepts a dict of VariableShard-like objects or raw dicts.\"\"\"
        now = time.time()
        for name, s in (shards or {}).items():
            try:
                # VariableShard dataclass style
                law = getattr(s, "law", None)
                if law is None and isinstance(s, dict):
                    law = s.get("law")
                if not isinstance(law, Law):
                    try:
                        law = Law(law)
                    except Exception:
                        law = Law.ENERGY

                val = getattr(s, "value", None)
                if val is None and isinstance(s, dict):
                    val = s.get("value", 0.0)
                val = float(val)

                conf = getattr(s, "confidence", 1.0)
                if isinstance(s, dict):
                    conf = s.get("confidence", conf)
                conf = float(conf)

                prov = getattr(s, "provenance", "observed")
                if isinstance(s, dict):
                    prov = s.get("provenance", prov)

                meta = getattr(s, "meta", None)
                if isinstance(s, dict):
                    meta = s.get("meta", meta)

                self.variables[str(name)] = StoredVar(
                    name=str(name),
                    value=val,
                    law=law,
                    confidence=conf,
                    provenance=str(prov),
                    ts=now,
                    meta=meta or {},
                )
            except Exception:
                # ignore malformed shard
                continue
        self._save()

    def export_state(self) -> Dict[str, Any]:
        return {
            "metadata": dict(self.metadata),
            "variables": {k: v.to_json() for k, v in self.variables.items()},
        }

    def snapshot(self) -> Dict[str, Any]:
        # deep-ish copy for small payloads
        return json.loads(json.dumps(self.export_state()))

    def restore(self, snapshot: Dict[str, Any]) -> None:
        self.metadata = snapshot.get("metadata") or {}
        vars_raw = snapshot.get("variables") or {}
        self.variables = {k: StoredVar.from_json(v) for k, v in vars_raw.items()}
        self._save()

    def summary(self) -> Dict[str, Any]:
        if not self.variables:
            return {"count": 0, "last_update": None}
        last = max(v.ts for v in self.variables.values())
        return {"count": len(self.variables), "last_update": last}
