import os
import time
from collections import defaultdict

try:
    import redis
except Exception:
    redis = None

class RateLimiter:
    def check(self, key: str, rpm: int | None = None) -> None:
        raise NotImplementedError

class InMemoryRateLimiter(RateLimiter):
    def __init__(self, default_rpm: int = 60):
        self.default_rpm = default_rpm
        self.window = 60
        self.buckets = defaultdict(lambda: [0, time.time()])

    def check(self, key: str, rpm: int | None = None) -> None:
        rpm = int(rpm if rpm is not None else self.default_rpm)
        if rpm <= 0:
            return
        count, start = self.buckets[key]
        now = time.time()
        if now - start >= self.window:
            self.buckets[key] = [1, now]
            return
        if count >= rpm:
            raise RuntimeError("Rate limit exceeded")
        self.buckets[key][0] += 1

class RedisRateLimiter(RateLimiter):
    def __init__(self, url: str, default_rpm: int = 60, prefix: str = "vector:rl"):
        if redis is None:
            raise RuntimeError("redis package not installed")
        self.default_rpm = default_rpm
        self.window = 60
        self.prefix = prefix
