import os
import time
from collections import defaultdict

try:
    import redis
except Exception:
    redis = None

class RateLimiter:
    def check(self, key: str, rpm: int | None = None) -> None:
        raise NotImplementedError

class InMemoryRateLimiter(RateLimiter):
    def __init__(self, default_rpm: int = 60):
        self.default_rpm = default_rpm
        self.window = 60
        self.buckets = defaultdict(lambda: [0, time.time()])

    def check(self, key: str, rpm: int | None = None) -> None:
        rpm = int(rpm if rpm is not None else self.default_rpm)
        if rpm <= 0:
            return
        count, start = self.buckets[key]
        now = time.time()
        if now - start >= self.window:
            self.buckets[key] = [1, now]
            return
        if count >= rpm:
            raise RuntimeError("Rate limit exceeded")
        self.buckets[key][0] += 1

class RedisRateLimiter(RateLimiter):
    def __init__(self, url: str, default_rpm: int = 60, prefix: str = "vector:rl"):
        if redis is None:
            raise RuntimeError("redis package not installed")
        self.default_rpm = default_rpm
        self.window = 60
        self.prefix = prefix
        self.r = redis.Redis.from_url(url, decode_responses=True)

    def check(self, key: str, rpm: int | None = None) -> None:
        rpm = int(rpm if rpm is not None else self.default_rpm)
        if rpm <= 0:
            return
        now = int(time.time())
        window = now // self.window
        k = f"{self.prefix}:{key}:{window}"
        val = self.r.incr(k, 1)
        if val == 1:
            self.r.expire(k, self.window + 2)
        if val > rpm:
            raise RuntimeError("Rate limit exceeded")

def build_rate_limiter() -> RateLimiter:
    default_rpm = int(os.environ.get("VECTOR_RATE_LIMIT_RPM", "60"))
    redis_url = os.environ.get("VECTOR_REDIS_URL", "").strip()
    if redis_url:
        return RedisRateLimiter(redis_url, default_rpm=default_rpm)
    return InMemoryRateLimiter(default_rpm=default_rpm)
