            "historical_replay": policy.historical_replay,
            "offline_continuity": policy.offline_continuity,
        },
        "usage_today": usage,
        "remaining_today": remaining,
    })

@app.post("/ingest")
def ingest():
    customer_id = request.environ.get("VECTOR_CUSTOMER_ID", "unknown")
    tier = request.environ.get("VECTOR_PLAN", "data_parser")
    policy = get_policy(tier)

    payload = _json()
    variables = payload.get("variables") or payload.get("data") or {}
    metadata = payload.get("metadata") or {}

    if not isinstance(variables, dict):
        return _error(400, "variables must be an object/dict", code="validation_error")

    # tier limit: max variables per ingest (count raw)
    if policy.max_variables_per_ingest is not None and len(variables) > int(policy.max_variables_per_ingest):
        return _error(
            400,
            "Too many variables for this tier",
            code="tier_limit_exceeded",
            tier=policy.key,
            required_tier=required_tier_for("max_variables_per_ingest"),
            limit="max_variables_per_ingest",
            max=int(policy.max_variables_per_ingest),
            got=int(len(variables)),
        )

    svc = _svc_for(customer_id)
    try:
        cleaned: Dict[str, float] = {}
        for k, v in variables.items():
            try:
                cleaned[str(k)] = float(v)
            except Exception:
                continue
        svc.ingest(cleaned, metadata=metadata)
    except Exception as e:
        return _error(500, f"Ingest failed: {e}", code="engine_error")

    _meter(customer_id, "ingest", meta=f"n={len(variables)}")
    return jsonify({"status": "accepted", "vault_revision": int(time.time())})

